// Función para quitar tildes y limpiar texto
const normalize = (str) =>
  str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase().trim();

const originalText = $json.text || '';
const text = normalize(originalText);

// Patrones: buscame, quiero, necesito, hay... [nicho] en [ciudad]
const regex = /\b(?:busc(a|ame|qu?ame)|quiero|necesito|hay)\s+(.*?)\s+en\s+(.+?)([.,]|$)/i;
const match = text.match(regex);

if (match && match[2] && match[3]) {
  const niche = match[2].trim();
  const city = match[3].trim();
  return [{ json: { niche, city, original: originalText } }];
} else {
  return [{ json: { error: '❌ No se pudo extraer nicho y ciudad.', original: originalText } }];
}

